const GOOGLE_SHEETS = [
'Animal', 'Bench', 'Planter', 'Fountain', 'Lamppost', 'Bathtub', 'Sink', 'Vanity', 'Fireplace', 'Table', 'Statue', 'MarbleSlab', '2026Instock', 'DoorSurround', 'Wall-Coverings', 'MarbleRangeHood', 'Moulding', 'StoneMosaicTile', 'MarbleMedallion', 'Exterior-Wall-Decoration'
// 'Test data'  // Uncomment for testing
];

return GOOGLE_SHEETS
  .filter(Boolean)  // Remove any empty/null values
  .map(sheet_name => ({ json: { sheet_name } }));

// ============================================
// CONFIGURATION
// ============================================
const CONFIG = {
  MAX_CREATE_ITEMS: 3,
  VENDOR: 'Marblebee',
  WEIGHT_UNIT: 'kg',
  DECIMAL_PLACES: 2,

  IMAGE_KEYS: [
    'IMAGE URL1',
    'IMAGE URL2',
    'IMAGE URL3',
    'IMAGE URL4',
    'IMAGE URL5',
    'IMAGE URL6',
    'IMAGE URL7',
    'IMAGE URL8',
    'IMAGE URL9',
    'IMAGE URL10'
  ],

  SHEET_NAME: $('ð Loop Through Sheets').item.json.sheet_name
};

// ============================================
// UTILITIES
// ============================================

const safeRound = (value, decimals = CONFIG.DECIMAL_PLACES) => {
  const num = parseFloat(value);
  return Number.isFinite(num)
    ? Number(num.toFixed(decimals))
    : '';
};

const cleanWeight = (weightRaw) => {
  const cleaned = String(weightRaw ?? '0').replace(/[^\d.]/g, '');
  return cleaned ? parseFloat(cleaned) : 0.0;
};

const safeNumeric = (value, defaultValue = 0) => {
  const num = parseFloat(value);
  return Number.isFinite(num)
    ? num
    : defaultValue;
};

const hasValue = (value) =>
  value !== undefined &&
  value !== null &&
  String(value).trim() !== '';


// ============================================
// SEO HELPERS
// ============================================

// Shopify handle formatter
const slugify = (text = '') =>
  String(text)
    .toLowerCase()
    .trim()
    .replace(/&/g, 'and')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .replace(/-{2,}/g, '-');


// URL HANDLE RULE:
// "{keyword}-{material}-{product-number}"
const buildHandle = (data) => {
  const keyword = data['Keywords (Luna)'] ?? '';
  const material = data.Material ?? '';
  const productNumber = data['Product No.'] ?? '';

  return slugify(
    `${keyword}-${material}-${productNumber}`
  );
};


// IMAGE ALT RULE:
// "{keyword} in {material} - Image {index}"
const buildAltText = (data, index) => {
  const keyword = data['Keywords (Luna)'].trim() ?? 'Marble Product';
  const material = data.Material.trim() ?? 'Natural Marble';

  return `${keyword} in ${material} - Image ${index}`;
};


// Build Shopify images with alt text
const extractImages = (data, keys) =>
  keys
    .filter(key => hasValue(data[key]))
    .map((key, index) => ({
      src: data[key],
      alt: buildAltText(data, index + 1)
    }));


// ============================================
// VALIDATION & OPERATION TYPE
// ============================================

const isReadyToPost = (data) => {
  const value = String(data?.Ready_to_post ?? '')
    .trim()
    .toLowerCase();

  return value === 'yes' || value === 'true';
};

const hasTitle = (data) =>
  hasValue(data?.Title_Shopify);

const getOperationType = (data) => {

  if (!isReadyToPost(data) || !hasTitle(data)) {
    return null;
  }

  const hasFieldsToUpdate = hasValue(data.Fields_to_update);
  const hasPublicUrl = hasValue(data.Shopify_Product_URL);
  const hasAdminUrl = hasValue(data.Shopify_Update_product_URL);

  // UPDATE
  if (
    hasFieldsToUpdate &&
    hasPublicUrl &&
    hasAdminUrl
  ) {
    return 'update';
  }

  // CREATE
  if (
    !hasFieldsToUpdate &&
    !hasPublicUrl &&
    !hasAdminUrl
  ) {
    return 'create';
  }

  return 'mark false';
};


// ============================================
// PRODUCT BUILDER
// ============================================

const buildProduct = (data, operation) => {

  const weight = safeRound(
    cleanWeight(data['Weight KG'])
  );

  const price = safeNumeric(
    data['Price IN USD $ (Jack)']
  );

  // ============================================
  // DIMENSIONS
  // ============================================

  const isFireplace =
    CONFIG.SHEET_NAME === 'Fireplace'  ||
    CONFIG.SHEET_NAME === 'Test data';

  const isWallCoverings =
    CONFIG.SHEET_NAME === 'Wall-Coverings'

  const isExteriorWallDecoration =
    CONFIG.SHEET_NAME === 'Exterior-Wall-Decoration'

  const isMarbleSlab =
    CONFIG.SHEET_NAME === 'MarbleSlab';

  const isMarbleRangeHood =
    CONFIG.SHEET_NAME === 'MarbleRangeHood';

  const isMoulding =
    CONFIG.SHEET_NAME === 'Moulding';

  const isStoneMosaicTile =
    CONFIG.SHEET_NAME === 'StoneMosaicTile';

  const isMarbleMedallion =
    CONFIG.SHEET_NAME === 'MarbleMedallion';

  const dimensions = isMarbleSlab || isWallCoverings || isStoneMosaicTile || isMarbleMedallion || isExteriorWallDecoration
    ? {
        l_cm: data['Length CM'] ?? '',
        w_cm: data['Width CM'] ?? '',
        t_cm: data['Thickness CM'] ?? '',

        l_in: safeRound(data['Length Inch']) ?? '',
        w_in: safeRound(data['Width Inch']),
        t_in: safeRound(data['Thickness Inch'])
      }
    : isFireplace || isMarbleRangeHood
    ? {
        d_cm: data['Depth CM'] ?? '',
        w_cm: data['Width CM'] ?? '',
        h_cm: data['Height CM'] ?? '',

        d_in: safeRound(data['Depth Inch']) ?? '',
        w_in: safeRound(data['Width Inch']),
        h_in: safeRound(data['Height Inch'])
      }
    : isMoulding
    ? {
        l_cm: data['Length CM'] ?? '',
        h_cm: data['Height CM'] ?? '',
        t_cm: data['Thickness CM'] ?? '',

        l_in: safeRound(data['Length Inch']) ?? '',
        h_in: safeRound(data['Height Inch']),
        t_in: safeRound(data['Thickness Inch'])
      }
    : {
        l_cm: data['Length CM'] ?? '',
        w_cm: data['Width CM'] ?? '',
        h_cm: data['Height CM'] ?? '',

        l_in: safeRound(data['Length Inch']) ?? '',
        w_in: safeRound(data['Width Inch']),
        h_in: safeRound(data['Height Inch'])
      };

  // ============================================
  // Opening Size For Fireplace
  // ============================================

  const opening_size = isFireplace
    ? {
        opening_w_cm: data['Width_CM'] ?? '',
        opening_h_cm: data['Height_CM'] ?? '',

        opening_w_in: safeRound(data['Width_Inch']),
        opening_h_in: safeRound(data['Height_Inch'])
      }
    : {}

  // ============================================
  // SEO
  // ============================================

  const seoTitle =
    data.Shopify_SEO_Title.trim() ??
    data.Title_Shopify.trim() ??
    '';

  const seoDescription =
    data.Shopify_SEO_Description.trim() ??
    '';

  const handle = buildHandle(data);

  // ============================================
  // RETURN PRODUCT
  // ============================================

  return {

    // Metadata
    row_number: data.row_number ?? 0,
    sheet_name: CONFIG.SHEET_NAME ?? '',
    updating_fields: data.Fields_to_update ?? '',
    operation,

    // URLs
    public_shopify_url:
      data.Shopify_Product_URL ?? '',

    admin_shopify_url:
      data.Shopify_Update_product_URL ?? '',

    // Dimensions
    ...dimensions,
    ...opening_size,

    // Shopify Product
    title: data.Title_Shopify.trim() ?? '',
    description: data.Description_Shopify.trim() ?? '',

    material: data.Material.trim() ?? '',
    product_number: data['Product No.'].trim() ?? '',

    weight,

    drain_diameter:
      data.Drain_Diameter ?? '',

    radius: data.Radius ?? '',
    surface: data.Surface ?? '',

    signature:
      data.Signature ?? '',

    // SEO

    seo_title: seoTitle,
    seo_description: seoDescription,
    handle,

    // Custom buttons
    material_catalog_url:
      data['Material Catalog URL'].trim() ?? '',

    care_guide_url:
      data['Care Guide URL'].trim() ?? '',

    cad_drawing_url:
      data['CAD Drawing URL'].trim() ?? '',

    // Etsy
    title_Etsy:
      data.Title_Etsy ?? '',

    description_Etsy:
      data.Description_Etsy ?? '',

    tags_Etsy:
      data.Tags_Etsy ?? '',

    who_made:
      data.who_made ?? '',

    when_made:
      data.when_made ?? '',

    product_type_Etsy:
      data.Etsy_type ?? '',

    quantity_Etsy:
      data.Etsy_quantity ?? 0,

    // Shopify
    vendor: CONFIG.VENDOR,

    product_type:
      data.Product_Type.trim() ?? 'Default',

    tags:
      data.Tags_Shopify.trim() ?? '',

    // Variants
    variants: [
      {
        requires_shipping: false,
        price,
        weight,
        weight_unit: CONFIG.WEIGHT_UNIT
      }
    ],

    // Images + ALT TEXT
    images: extractImages(
      data,
      CONFIG.IMAGE_KEYS
    )
  };
};


// ============================================
// MAIN PROCESSING
// ============================================

// Step 1
const categorized = items
  .map(item => {

    const data = item.json ?? {};
    const operation = getOperationType(data);

    return { data, operation };

  })
  .filter(({ operation }) => operation !== null);


// Step 2
const createItems =
  categorized.filter(
    ({ operation }) => operation === 'create'
  );

const updateItems =
  categorized.filter(
    ({ operation }) => operation === 'update'
  );

const mark_false =
  categorized.filter(
    ({ operation }) => operation === 'mark false'
  );


// Step 3
const limitedCreateItems =
  createItems.slice(0, CONFIG.MAX_CREATE_ITEMS);


// Step 4
const selectedItems = [
  ...limitedCreateItems,
  ...updateItems,
  ...mark_false
];


// Step 5
const outputItems = selectedItems.map(
  ({ data, operation }) => ({

    json: {

      collection_id1: String(
        data.Collection_ID1.trim() ?? ''
      ),

      collection_id2: String(
        data.Collection_ID2.trim() ?? ''
      ),

      collection_id3: String(
        data.Collection_ID3.trim() ?? ''
      ),

      operation,

      product: buildProduct(
        data,
        operation
      )
    }
  })
);


return outputItems.length > 0
  ? outputItems
  : [
      {
        json: {
          sheet_name: CONFIG.SHEET_NAME,
          operation: 'None'
        }
      }
    ];

// ============================================
// CONFIGURATION
// ============================================
const CONFIG = {
  DIMENSION_FIELDS: new Set([
    'Lenght CM','Width CM','Height CM','Depth CM', 'Thickness CM',
    'Length Inch','Width Inch','Height Inch','Depth Inch', 'Thickness Inch'
  ]),
  OPENING_SIZE_FIELDS: new Set([
    'Width_CM', 'Height_CM', 'Width_Inch', 'Height_Inch',
  ]),
  CONTENT_FIELDS: new Set([
    'Material','Description_Shopify','Weight KG','Product No.',
    'Surface','Drain_Diameter','Radius','Signature'
  ]),
  TITLE_FIELD: 'Title_Shopify',
  TAGS_SHOPIFY: 'Tags_Shopify',
  COLLECTION_ID1: 'Collection_ID1',
  COLLECTION_ID2: 'Collection_ID2',
  COLLECTION_ID3: 'Collection_ID3',
  PRICE_FIELD: 'Price IN USD $ (Jack)',
  WEIGHT_FIELD: 'Weight KG',

  // SEO Fields
  SEO_TITLE_FIELD: 'Shopify_SEO_Title',
  SEO_DESC_FIELD: 'Shopify_SEO_Description',

  // â NEW (metafield trigger fields)
  META_URL_FIELDS: new Set([
    'Material Catalog URL',
    'Care Guide URL',
    'CAD Drawing URL'
  ]),

  PATTERNS: {
    PRODUCT_ID: /\/products\/(\d+)/,
    VARIANT_ID: /[?&]variant=(\d+)/
  }
};

const ALL_BODY_FIELDS = new Set([...CONFIG.DIMENSION_FIELDS,...CONFIG.OPENING_SIZE_FIELDS, ...CONFIG.CONTENT_FIELDS]);

// ============================================
// UTILITIES
// ============================================

const normalizeUrl = (url) => {
  if (!url) return '';
  return String(url).trim().replace(/\\+$/, '');
};

const extractId = (url, pattern) => url?.match(pattern)?.[1] ?? '';
const getVariantId = (url) => extractId(url, CONFIG.PATTERNS.VARIANT_ID);
const extractProductId = (url) => extractId(url, CONFIG.PATTERNS.PRODUCT_ID);

const parseUpdateFields = (fieldsStr) => 
  fieldsStr?.split(',').map(f => f.trim()).filter(Boolean) ?? [];

const shouldUpdateBody = (updateList) => 
  updateList.some(field => ALL_BODY_FIELDS.has(field));

const hasValue = (v) => {
  if (Array.isArray(v)) return v.length > 0;
  if (typeof v === 'object' && v !== null) return Object.keys(v).length > 0;
  return v !== undefined && v !== null && v !== '';
};

const field = (label, value, suffix = '') => 
  hasValue(value) ? `<p><strong>${label}:</strong> ${value}${suffix}</p>` : '';

// ============================================
// HTML BUILDER
// ============================================

const buildDimensionLine = (dims) => 
  dims.filter(([, v]) => hasValue(v))
      .map(([label, v, unit]) => `<strong>${label}:</strong> ${v} ${unit}`)
      .join(' &nbsp; ');

const buildBodyHtml = (p) => {
  const isFireplace = p.sheet_name === 'Fireplace' || p.sheet_name === 'Test data';
  const isWallCoverings = p.sheet_name === 'Wall-Coverings';
    const isExteriorWallDecoration = p.sheet_name === 'Exterior-Wall-Decoration';
  const isMarbleSlab = p.sheet_name === 'MarbleSlab';
  const isMarbleRangeHood = p.sheet_name === 'MarbleRangeHood';
  const isMoulding = p.sheet_name === 'Moulding';
  const isStoneMosaicTile = p.sheet_name === 'StoneMosaicTile';
  const isMarbleMedallion = p.sheet_name === 'MarbleMedallion';

  // =========================
  // SINGLE SOURCE DIM CONFIG
  // =========================
  const dimensionConfig = isMarbleSlab || isWallCoverings || isStoneMosaicTile || isMarbleMedallion || isExteriorWallDecoration
    ? [
        { label: 'Length', cm: p.l_cm, inch: p.l_in },
        { label: 'Width', cm: p.w_cm, inch: p.w_in },
        { label: 'Thickness', cm: p.t_cm, inch: p.t_in }
      ]
    : isFireplace || isMarbleRangeHood
    ? [
        { label: 'Width', cm: p.w_cm, inch: p.w_in },
        { label: 'Height', cm: p.h_cm, inch: p.h_in },
        { label: 'Depth', cm: p.d_cm, inch: p.d_in },
      ]
    : isMoulding
    ? [
        { label: 'Length', cm: p.l_cm, inch: p.l_in },
        { label: 'Height', cm: p.h_cm, inch: p.h_in },
        { label: 'Thickness', cm: p.t_cm, inch: p.t_in }
      ]
    : [
        { label: 'Length', cm: p.l_cm, inch: p.l_in },
        { label: 'Width', cm: p.w_cm, inch: p.w_in },
        { label: 'Height', cm: p.h_cm, inch: p.h_in }
      ];

  // =========================
  // BUILD LINES
  // =========================
  const cmLine = buildDimensionLine(
    dimensionConfig.map(d => [d.label, d.cm, 'cm'])
  );

  const inLine = buildDimensionLine(
    dimensionConfig.map(d => [d.label, d.inch, 'In'])
  );

  // =========================
  // SINGLE SOURCE Openiing Size CONFIG
  // =========================
  const openingSizeConfig = isFireplace
    ? [
        { label: 'Width', cm: p.opening_w_cm, inch: p.opening_w_in },
        { label: 'Height', cm: p.opening_h_cm, inch: p.opening_h_in },
      ]
    : [];

  // =========================
  // BUILD LINES
  // =========================
  const cmOpeningLine = buildDimensionLine(
    openingSizeConfig.map(o => [o.label, o.cm, 'cm'])
  );

  const inOpeningLine = buildDimensionLine(
    openingSizeConfig.map(o => [o.label, o.inch, 'In'])
  );

  return [
    (cmLine || inLine) && '<p><strong>Dimensions</strong></p>',
    cmLine && `<p>${cmLine}</p>`,
    inLine && `<p>${inLine}</p>`,
    (cmOpeningLine || inOpeningLine) && '<p><strong>Opening Size</strong></p>',
    cmOpeningLine && `<p>${cmOpeningLine}</p>`,
    inOpeningLine && `<p>${inOpeningLine}</p>`,
    field('Material', p.material),
    field('Weight', p.weight, ' kg'),
    hasValue(p.description) && `<p>${p.description}</p>`,
    field('Drain Diameter', p.drain_diameter),
    field('Radius', p.radius),
    field('Surface', p.surface),
    p.signature,
    field('Product Number', p.product_number)
  ].filter(Boolean).join('');
};

// ============================================
// BUILDERS
// ============================================

const buildVariants = (product, updateList) => {
  const variant = {};

  const variantId = getVariantId(product.public_shopify_url);
  if (variantId) variant.id = variantId;

  if (updateList.includes(CONFIG.PRICE_FIELD)) {
    variant.price = product.variants?.[0]?.price;
  }

  if (updateList.includes(CONFIG.WEIGHT_FIELD)) {
    variant.weight = product.weight;
  }

  return Object.keys(variant).length > 0 ? [variant] : [];
};

const hasAnyImageUpdate = (updateList) =>
  updateList.some(f => /^IMAGE URL\d+$/.test(f));

const buildImages = (product, updateList) => {
  if (!hasAnyImageUpdate(updateList)) return [];
  if (!Array.isArray(product.images) || product.images.length === 0) return [];

  return product.images
    .filter(img => img?.src)
    .map(img => ({ src: img.src, alt: img.alt }));
};

// ============================================
// CORE UPDATE PAYLOAD
// ============================================

const buildUpdatePayload = (product, updateList) => {
  const input = $input.first().json;

  const payload = {
    id: extractProductId(product.admin_shopify_url),
  };

  // ======================
  // BODY HTML
  // ======================
  if (shouldUpdateBody(updateList)) {
    const bodyHtml = buildBodyHtml(product);
    if (bodyHtml) payload.body_html = bodyHtml;
  }

  // ======================
  // VARIANTS
  // ======================
  const variants = buildVariants(product, updateList);
  if (variants.length > 0) payload.variants = variants;

  // ======================
  // TITLE
  // ======================
  if (updateList.includes(CONFIG.TITLE_FIELD) && product.title) {
    payload.title = product.title;
  }

  // ======================
  // TAGS
  // ======================
  if (updateList.includes(CONFIG.TAGS_SHOPIFY) && input.product?.tags) {
    payload.tags = input.product.tags;
  }

  // ======================
  // IMAGES
  // ======================
  const images = buildImages(product, updateList);
  if (images.length > 0) payload.images = images;

  // ======================
  // COLLECTIONS
  // ======================
  if (
    updateList.includes(CONFIG.COLLECTION_ID1) ||
    updateList.includes(CONFIG.COLLECTION_ID2) ||
    updateList.includes(CONFIG.COLLECTION_ID3)
  ) {
    payload.collection_id1 = input.collection_id1 ?? '';
    payload.collection_id2 = input.collection_id2 ?? '';
    payload.collection_id3 = input.collection_id3 ?? '';
  }

  // ======================
  // â METAFIELD DATA (CRITICAL)
  // ======================
  if (updateList.includes('Material Catalog URL')) {
    payload.material_catalog_url =    normalizeUrl(product.material_catalog_url) ?? '';
   }

  if (updateList.includes('Care Guide URL')) {
     payload.care_guide_url = normalizeUrl(product.care_guide_url)      ?? '';
  }

  if (updateList.includes('CAD Drawing URL')) {
    payload.cad_drawing_url = normalizeUrl(product.cad_drawing_url) ?? '';
  }

  // ======================
  // â SEO FIELDS 
  // ======================
  const metafields = [];

  if (updateList.includes(CONFIG.SEO_TITLE_FIELD) && hasValue(product.seo_title)) {
    metafields.push({
      namespace: "global",
      key: "title_tag",
      type: "single_line_text_field",
      value: product.seo_title
    });
  }

  if (updateList.includes(CONFIG.SEO_DESC_FIELD) && hasValue(product.seo_description)) {
    metafields.push({
      namespace: "global",
      key: "description_tag",
      type: "multi_line_text_field",
      value: product.seo_description
    });
  }

  if (metafields.length > 0) {
    payload.metafields = metafields;
  }

  return payload;
};

// ============================================
// MAIN
// ============================================

const product = items?.[0]?.json?.product;
if (!product) return [];

const updateFields = parseUpdateFields(product.updating_fields);
const updatePayload = buildUpdatePayload(product, updateFields);

return [{ json: { product: updatePayload } }];

const sheet = $('ð Route: Create or Update').item.json.product.sheet_name;
const row_number = $('ð Route: Create or Update').item.json.product.row_number;

return [
  {
    json: {
      "sheet_name":sheet,
      "row_number":row_number,
      "Ready_to_post": "no",
      "Fields_to_update": "",
      "last_update_time": $now
    },
  },
];

// ============================================
// CONFIGURATION
// ============================================
const CONFIG = {
  ADMIN_BASE_URL: 'https://admin.shopify.com/store/marblebee/products/',
  PRODUCT_BASE_URL: 'https://marblebee.myshopify.com/products/'
};

// ============================================
// EXTRACT DATA
// ============================================
const routeData = $('ð Route: Create or Update').first()?.json?.product ?? {};
const product = items[0]?.json?.product ?? {};
const variant = product.variants?.[0] ?? {};

// ============================================
// BUILD URLS
// ============================================
const shopifyProductUrl = product.public_shopify_url || 
  `${CONFIG.PRODUCT_BASE_URL}${product.handle ?? ''}?variant=${variant.id ?? ''}`;

const shopifyUpdateUrl = product.admin_shopify_url || 
  `${CONFIG.ADMIN_BASE_URL}${product.id ?? ''}`;

// ============================================
// BUILD OUTPUT
// ============================================
return [{
  json: {
    sheet_name: routeData.sheet_name ?? '',
    row_number: routeData.row_number ?? '',
    'Title_Shopify': (product.title ?? '').trim(),
    'Shopify_Product_URL': shopifyProductUrl,
    'Shopify_Update_product_URL': shopifyUpdateUrl,
    'Ready_to_post': 'no',
    'Fields_to_update': '',
    'create_time': $now
  }
}];

// Get collection IDs from the Route node
const collectionIds = [
  $('ð Route: Create or Update').item?.json?.collection_id1,
  $('ð Route: Create or Update').item?.json?.collection_id2,
  $('ð Route: Create or Update').item?.json?.collection_id3,
].filter(id => id !== null && id !== undefined && id !== '');

// Get product ID from current input
const productId = $input.first().json.product.id;

// If no valid collections â do nothing
if (collectionIds.length === 0) {
  return [];
}

// Create one item per valid collection
return collectionIds.map(collection_id => ({
  collect: {
    product_id: productId,
    collection_id: String(collection_id),
  }
}));

// ===== Get previous node data =====
const nodeData = $('ð Format Update Request').item?.json || {};

// ===== Get product_id safely =====
const product_id = $input.first()?.json?.collects?.[0]?.product_id ?? null;

// ===== Source collection IDs (1,2,3) =====
const sourceCollectionIds = [
  nodeData?.product?.collection_id1,
  nodeData?.product?.collection_id2,
  nodeData?.product?.collection_id3,
]
  .filter(v => v !== undefined && v !== null && String(v).trim() !== '')
  .map(String);

// ===== Input collects =====
const collects = $input.first()?.json?.collects || [];
const collectCollectionIds = collects
  .map(c => c?.collection_id)
  .filter(v => v !== undefined && v !== null)
  .map(String);

// ===== 1ï¸â£ DELETE =====
// Exists in collects but NOT in sourceCollectionIds
const collection_id_for_delete = collects
  .filter(c => c && !sourceCollectionIds.includes(String(c.collection_id)))
  .map(c => ({
    collect_id: String(c.id),
    product_id: product_id
  }));

// ===== 2ï¸â£ UPDATE =====
// Exists in sourceCollectionIds but NOT in collects
const collection_id_to_update = sourceCollectionIds
  .filter(id => !collectCollectionIds.includes(id))
  .map(id => ({
    collect_id: id,
    product_id: product_id
  }));

// ===== Build FINAL OUTPUT =====
const output = [];

// ---- DELETE FORMAT ----
if (collection_id_for_delete.length > 0) {
  for (const c of collection_id_for_delete) {
