return output;

const input = $input.first().json;

// Always safe unwrap (n8n sometimes wraps arrays)
const metafields = input.metafields || [];

// IMPORTANT: only take fields that actually exist in update node
const productWrapper = $('ð Format Update Request').item.json;
const product = productWrapper.product || {};

// Only include fields that are actually present (not undefined)
const sheetData = {};

if (product.hasOwnProperty('material_catalog_url')) {
  sheetData.material_catalog_url = product.material_catalog_url;
}

if (product.hasOwnProperty('care_guide_url')) {
  sheetData.care_guide_url = product.care_guide_url;
}

if (product.hasOwnProperty('cad_drawing_url')) {
  sheetData.cad_drawing_url = product.cad_drawing_url;
}

const operations = [];

// Only iterate actual incoming fields
for (const [key, newValueRaw] of Object.entries(sheetData)) {

  const newValue = (newValueRaw || '').toString().trim();

  const existingField = metafields.find(
    m => m.namespace === "custom" && m.key === key
  );

  // =========================
  // DELETE (ONLY if explicitly empty string)
  // =========================
  if (newValue === '' && existingField) {
    operations.push({
      type: "delete",
      id: existingField.id
    });
    continue;
  }

  // =========================
  // CREATE
  // =========================
  if (newValue !== '' && !existingField) {
    operations.push({
      type: "create",
      payload: {
        metafield: {
          namespace: "custom",
          key,
          type: "url",
          value: newValue,
          owner_id: product.id,
          owner_resource: "product"
        }
      }
    });
    continue;
  }

  // =========================
  // UPDATE
  // =========================
  if (
    newValue !== '' &&
    existingField &&
    existingField.value !== newValue
  ) {
    operations.push({
      type: "update",
      id: existingField.id,
      payload: {
        metafield: {
          id: existingField.id,
          value: newValue,
          type: "url"
        }
      }
    });
  }
}

// =========================
// SAFE OUTPUT
// =========================
if (operations.length === 0) {
  return [{ json: { message: "No metafield changes detected" } }];
}

return operations.map(op => ({ json: op }));

// ============================================
// CONFIGURATION
// ============================================
const CONFIG = {
  METADATA_FIELDS: new Set([
    'l_cm','w_cm','h_cm','d_cm','t_cm',
    'l_in','w_in','h_in','d_in','t_in',
    'opening_w_cm', 'opening_h_cm', 'opening_w_in', 'opening_h_in',
    'material','description',
    'weight','product_number',
    'sheet_name','row_number',
    'drain_diameter','radius',
    'surface','signature',
    'material_catalog_url',
    'care_guide_url',
    'cad_drawing_url',
    'seo_title',
    'seo_description'
  ])
};

// ============================================
// HELPERS
// ============================================
const hasValue = (v) =>
  v !== null &&
  v !== undefined &&
  v !== '' &&
  v !== 0 &&
  v !== '0';

// ============================================
// SEO NORMALIZER (IMPORTANT FIX)
// ============================================
const getSeoTitle = (p) => {
  return (
    p?.seo_title ||
    ''
  );
};

const getSeoDescription = (p) => {
  return (
    p?.seo_description ||
    p?.description ||
    ''
  );
};

// ============================================
// BUILD METAFIELDS
// ============================================
const buildMetafields = (p) => {
  const metafields = [];

  // -------------------------
  // Custom URLs
  // -------------------------
  if (hasValue(p.material_catalog_url)) {
    metafields.push({
      namespace: "custom",
      key: "material_catalog_url",
      type: "url",
      value: p.material_catalog_url
    });
  }

  if (hasValue(p.care_guide_url)) {
    metafields.push({
      namespace: "custom",
      key: "care_guide_url",
      type: "url",
      value: p.care_guide_url
    });
  }

  if (hasValue(p.cad_drawing_url)) {
    metafields.push({
      namespace: "custom",
      key: "cad_drawing_url",
      type: "url",
      value: p.cad_drawing_url
    });
  }

  // -------------------------
  // SEO FIELDS (ROBUST FIX)
  // -------------------------
  const seoTitle = getSeoTitle(p);
  const seoDescription = getSeoDescription(p);

  if (hasValue(seoTitle)) {
    metafields.push({
      namespace: "global",
      key: "title_tag",
      type: "single_line_text_field",
      value: String(seoTitle).slice(0, 70)
    });
  }

  if (hasValue(seoDescription)) {
    metafields.push({
      namespace: "global",
      key: "description_tag",
      type: "multi_line_text_field",
      value: String(seoDescription).slice(0, 320)
    });
  }

  return metafields;
};

// ============================================
// BODY HTML BUILDER
// ============================================
const field = (label, value, suffix = '') =>
  hasValue(value)
    ? `<p><strong>${label}:</strong> ${value}${suffix}</p>`
    : '';

const buildDimLine = (items, unit) => {
  const line = items
    .filter(([, v]) => hasValue(v))
    .map(([label, v]) => `<strong>${label}:</strong> ${v} ${unit}`)
    .join('&nbsp;&nbsp;');

  return hasValue(line) ? `<p>${line}</p>` : '';
};

const buildBodyHtml = (p) => {
  const sections = [];

  const isFireplace = p.sheet_name === 'Fireplace'  || p.sheet_name === 'Test data';
  const isWallCoverings = p.sheet_name === 'Wall-Coverings';
  const isExteriorWallDecoration = p.sheet_name === 'Exterior-Wall-Decoration';
  const isMarbleSlab = p.sheet_name === 'MarbleSlab';
  const isMarbleRangeHood =
    p.sheet_name === 'MarbleRangeHood';
  const isMoulding =
    p.sheet_name === 'Moulding';
  const isStoneMosaicTile =
    p.sheet_name === 'StoneMosaicTile';
  const isMarbleMedallion =
    p.sheet_name === 'MarbleMedallion';

  const dimensionConfig = isMarbleSlab || isWallCoverings || isStoneMosaicTile || isMarbleMedallion || isExteriorWallDecoration
    ? [
        { label: 'Length', cm: p.l_cm, inch: p.l_in },
        { label: 'Width', cm: p.w_cm, inch: p.w_in },
        { label: 'Thickness', cm: p.t_cm, inch: p.t_in }
      ]
    : isFireplace || isMarbleRangeHood
    ? [
        { label: 'Width', cm: p.w_cm, inch: p.w_in },
        { label: 'Height', cm: p.h_cm, inch: p.h_in },
        { label: 'Depth', cm: p.d_cm, inch: p.d_in },
      ]
    : isMoulding
    ? [
        { label: 'Length', cm: p.l_cm, inch: p.l_in },
        { label: 'Height', cm: p.h_cm, inch: p.h_in },
        { label: 'Thickness', cm: p.t_cm, inch: p.t_in }
      ]
    : [
        { label: 'Length', cm: p.l_cm, inch: p.l_in },
        { label: 'Width', cm: p.w_cm, inch: p.w_in },
        { label: 'Height', cm: p.h_cm, inch: p.h_in }
      ];

  const cmDims = buildDimLine(
    dimensionConfig.map(d => [d.label, d.cm]),
    'cm'
  );

  const inDims = buildDimLine(
    dimensionConfig.map(d => [d.label, d.inch]),
    'In'
  );

  if (cmDims || inDims) {
    sections.push('<p><strong>Dimensions</strong></p>');
    if (cmDims) sections.push(cmDims);
    if (inDims) sections.push(inDims);
  }

  const openingSizeConfig = isFireplace
    ? [
        { label: 'Width', cm: p.opening_w_cm, inch: p.opening_w_in },
        { label: 'Height', cm: p.opening_h_cm, inch: p.opening_h_in },
      ]
    : [];

  const cmOpeningSize = buildDimLine(
    openingSizeConfig.map(o => [o.label, o.cm]),
    'cm'
  );

  const inOpeningSize = buildDimLine(
    openingSizeConfig.map(o => [o.label, o.inch]),
    'In'
  );

  if (cmOpeningSize || inOpeningSize) {
    sections.push('<p><strong>Opening Size</strong></p>');
    if (cmOpeningSize) sections.push(cmOpeningSize);
    if (inOpeningSize) sections.push(inOpeningSize);
  }

  if (hasValue(p.material)) sections.push(field('Material', p.material));
  if (hasValue(p.weight)) sections.push(field('Weight', p.weight, ' kg'));
  if (hasValue(p.description)) sections.push(`<p>${p.description}</p>`);
  if (hasValue(p.drain_diameter)) sections.push(field('Drain Diameter', p.drain_diameter));
  if (hasValue(p.radius)) sections.push(field('Radius', p.radius));
  if (hasValue(p.surface)) sections.push(field('Surface', p.surface));
  if (hasValue(p.signature)) sections.push(p.signature);
  if (hasValue(p.product_number)) sections.push(field('Product Number', p.product_number));

  return sections.join('');
};

// ============================================
// MAIN
// ============================================
const product = items?.[0]?.json?.product;
if (!product) return [];

const bodyHtml = buildBodyHtml(product);
const metafields = buildMetafields(product);

// Safe handle fallback
const handleFallback =
  product.handle ||
  `${product.title || 'product'}-${product.material || ''}-${product.product_number || ''}`
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '');

const cleanedProduct = Object.fromEntries(
  Object.entries({
    ...product,

    handle: handleFallback,

    ...(hasValue(bodyHtml) ? { body_html: bodyHtml } : {}),
    ...(metafields.length > 0 ? { metafields } : {})
  }).filter(([key]) => !CONFIG.METADATA_FIELDS.has(key))
);

return [
  {
    json: {
      product: cleanedProduct
    }
  }
];
